particlesJS('particles-js', { "particles": { "number": { "value": 80, "density": { "enable": !0, "value_area": 800 } }, "color": { "value": "#a11d21" }, "shape": { "type": "circle", "stroke": { "width": 0, "color": "#000000" }, "polygon": { "nb_sides": 5 }, "image": { "src": "img/github.svg", "width": 100, "height": 100 } }, "opacity": { "value": 0.5, "random": !1, "anim": { "enable": !1, "speed": 1, "opacity_min": 0.1, "sync": !1 } }, "size": { "value": 3, "random": !0, "anim": { "enable": !1, "speed": 40, "size_min": 0.1, "sync": !1 } }, "line_linked": { "enable": !0, "distance": 150, "color": "#ffffff", "opacity": 0.4, "width": 1 }, "move": { "enable": !0, "speed": 2, "direction": "none", "random": !1, "straight": !1, "out_mode": "out", "bounce": !1, "attract": { "enable": !1, "rotateX": 600, "rotateY": 1200 } } }, "interactivity": { "detect_on": "canvas", "events": { "onhover": { "enable": !1, "mode": "repulse" }, "onclick": { "enable": !0, "mode": "push" }, "resize": !0 }, "modes": { "grab": { "distance": 400, "line_linked": { "opacity": 1 } }, "bubble": { "distance": 400, "size": 40, "duration": 2, "opacity": 8, "speed": 3 }, "repulse": { "distance": 200, "duration": 0.4 }, "push": { "particles_nb": 4 }, "remove": { "particles_nb": 2 } } }, "retina_detect": !0 }, function () { console.log('callback - particles.js config loaded') }); const textArray = ["Researcher", "Computer Scientist", "Programmer"]; const typingDelay = 100; const erasingDelay = 50; const newTextDelay = 1000; let textIndex = 0; let charIndex = 0; const typedTextSpan = document.getElementById("typewriter"); function type() { if (charIndex < textArray[textIndex].length) { typedTextSpan.textContent += textArray[textIndex].charAt(charIndex); charIndex++; setTimeout(type, typingDelay) } else { setTimeout(erase, newTextDelay) } }
function erase() { if (charIndex > 0) { typedTextSpan.textContent = textArray[textIndex].substring(0, charIndex - 1); charIndex--; setTimeout(erase, erasingDelay) } else { textIndex = (textIndex + 1) % textArray.length; setTimeout(type, typingDelay) } }
document.addEventListener("DOMContentLoaded", () => { setTimeout(type, newTextDelay) }); (function () { [...document.querySelectorAll(".control")].forEach(button => { button.addEventListener("click", function () { document.querySelector(".active-btn").classList.remove("active-btn"); this.classList.add("active-btn"); document.querySelector(".active").classList.remove("active"); document.getElementById(button.dataset.id).classList.add("active") }) }) })(); window.addEventListener('load', () => { const loader = document.getElementById('loader'); setTimeout(() => { loader.classList.add('fade-out') }, 3000) }); setTimeout(() => { const loader = document.getElementById('loader'); if (loader && !loader.classList.contains('fade-out')) { loader.classList.add('fade-out') } }, 5000)